//# Pipeline FIFO Buffer

// Decouples two sides of a ready/valid handshake to allow back-to-back
// transfers without a combinational path between input and output, thus
// pipelining the path to improve concurrency and/or timing. *Any FIFO depth
// is allowed, not only powers-of-2.* The input-to-output latency is 2 cycles.
// *Can function as a Circular Buffer.*

// Since a FIFO buffer stores variable amounts of data, it will smooth out
// irregularities in the transfer rates of the input and output interfaces,
// and when used in pipeline loops, can store enough data to prevent
// artificial deadlocks (re: [Kahn Process
// Networks](https://en.wikipedia.org/wiki/Kahn_process_networks#Boundedness_of_channels)
// with bounded channels).

// *This module is a variation of the asynchronous [CDC FIFO
// Buffer](./CDC_FIFO_Buffer.html), directly derived from Clifford E.
// Cummings' <a
// href="http://www.sunburst-design.com/papers/CummingsSNUG2002SJ_FIFO1.pdf">Simulation
// and Synthesis Techniques for Asynchronous FIFO Design</a>, SNUG 2002, San
// Jose.*

//## Circular Buffer Mode

// Normally, a FIFO buffer that is full will not complete another input
// handshake until a data item has been read out. You can think of this as
// buffering the *earliest* values from the pipeline.

// Setting `CIRCULAR_BUFFER` parameter to a non-zero value changes the
// behaviour at the input: the input handshake can always complete, discarding
// the oldest data already in the buffer even if it was never read out.  You
// can think of this as buffering the *latest* values from the pipeline.  This
// is a circular buffer.

// However, data at the buffer output can only be read out *once*, as usual,
// until updated again by data from inside the buffer, possibly in the same
// clock cycle. Simultaneous input and output handshakes are possible in
// Circular Buffer Mode since `input_ready` no longer depends on the
// empty/full state of the buffer (which forces alternation of input and
// output handshakes), nor on the state of the output handshake (which is
// disallowed to prevent creating a combinational path between input and
// output).

//## Parameters, Ports, and Initializations

`default_nettype none

module Pipeline_FIFO_Buffer
#(
    parameter WORD_WIDTH                = 0,
    parameter DEPTH                     = 0,
    parameter RAMSTYLE                  = "",
    parameter CIRCULAR_BUFFER           = 0         // non-zero to enable
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire                        input_valid,
    output  reg                         input_ready,
    input   wire    [WORD_WIDTH-1:0]    input_data,

    output  wire                        output_valid,
    input   wire                        output_ready,
    output  wire    [WORD_WIDTH-1:0]    output_data
);

    initial begin
        input_ready = 1'b1; // Empty at start, so accept data
    end

//## Constants

// From the FIFO `DEPTH`, we derive the bit width of the buffer addresses and
// construct the constants we work with.

    `include "clog2_function.vh"

    localparam WORD_ZERO    = {WORD_WIDTH{1'b0}};

    localparam ADDR_WIDTH   = clog2(DEPTH);
    localparam ADDR_ONE     = {{ADDR_WIDTH-1{1'b0}},1'b1};
    localparam ADDR_ZERO    = {ADDR_WIDTH{1'b0}};
    localparam ADDR_LAST    = DEPTH-1;

//## Data Path

// The buffer itself is a *synchronous* dual-port memory: one write port to
// insert data, and one read port to concurrently remove data, both clocked.
// Typically this memory will be a dedicated Block RAM, but can also be built
// from LUT RAM if the width and depth are small, or even plain registers for
// very small cases. Set the `RAMSTYLE` parameter as required.

// **NOTE**: write-forwarding logic is not necessary, since in normal mode
// there will never be a concurrent read and write to the same address, and in
// Circular Buffer Mode, a concurrent read and write to the same address (when
// the buffer is already full) always returns the stored data, not the data
// being written. Guide your CAD tool as necessary in each case about
// read/write address collisions, so you can obtain the highest possible
// operating frequency. 

// We initialize the read/write enables to zero, signifying an idle system.

    reg                     buffer_wren = 1'b0;
    wire [ADDR_WIDTH-1:0]   buffer_write_addr;

    reg                     buffer_rden = 1'b0;
    wire [ADDR_WIDTH-1:0]   buffer_read_addr;

    RAM_Simple_Dual_Port
    #(
        .WORD_WIDTH         (WORD_WIDTH),
        .ADDR_WIDTH         (ADDR_WIDTH),
        .DEPTH              (DEPTH),
        .RAMSTYLE           (RAMSTYLE),
        .READ_NEW_DATA      (0),
        .RW_ADDR_COLLISION  ("no"),
        .USE_INIT_FILE      (0),
        .INIT_FILE          (),
        .INIT_VALUE         (WORD_ZERO)
    )
    buffer
    (
        .clock          (clock),
        .wren           (buffer_wren),
        .write_addr     (buffer_write_addr),
        .write_data     (input_data),

        .rden           (buffer_rden),
        .read_addr      (buffer_read_addr),
        .read_data      (output_data)
    );

//### Read/Write Address Counters

// The buffer read and write addresses are stored in counters which both start
// at (and `clear` to) `ADDR_ZERO`.  Each counter can only increment by
// `ADDR_ONE` at each read or write, and will wrap around to `ADDR_ZERO` if
// incremented past a value of `DEPTH-1`, labelled as `ADDR_LAST` (`load`
// overrides `run`). *The depth can be any positive number, not only
// a power-of-2.

    reg increment_buffer_write_addr = 1'b0;
    reg load_buffer_write_addr      = 1'b0;

    Counter_Binary
    #(
        .WORD_WIDTH     (ADDR_WIDTH),
        .INCREMENT      (ADDR_ONE),
        .INITIAL_COUNT  (ADDR_ZERO)
    )
    write_address
    (
        .clock          (clock),
        .clear          (clear),
        .up_down        (1'b0), // 0/1 --> up/down
        .run            (increment_buffer_write_addr),
        .load           (load_buffer_write_addr),
        .load_count     (ADDR_ZERO),
        .carry_in       (1'b0),
        // verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        // verilator lint_on  PINCONNECTEMPTY
        .count          (buffer_write_addr)
    );

    reg increment_buffer_read_addr = 1'b0;
    reg load_buffer_read_addr      = 1'b0;

    Counter_Binary
    #(
        .WORD_WIDTH     (ADDR_WIDTH),
        .INCREMENT      (ADDR_ONE),
        .INITIAL_COUNT  (ADDR_ZERO)
    )
    read_address
    (
        .clock          (clock),
        .clear          (clear),
        .up_down        (1'b0), // 0/1 --> up/down
        .run            (increment_buffer_read_addr),
        .load           (load_buffer_read_addr),
        .load_count     (ADDR_ZERO),
        .carry_in       (1'b0),
        // verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        // verilator lint_on  PINCONNECTEMPTY
        .count          (buffer_read_addr)
    );

//### Wrap-Around Bits

// To distinguish between the empty buffer and full buffer cases, which both
// identically show as equal read and write buffer addresses, we keep track of
// each time an address wraps around to zero by toggling a bit.  *The
// addresses never pass eachother.* 

// If the write address runs ahead of the read address enough to wrap-around
// and reach the read address from behind, the buffer is full and all writes
// to the buffer halt until after a read happens (except in Circular Buffer
// Mode). We detect this because the write address will have wrapped-around
// one more time than the read address, so their wrap-around bits will be
// different.

// Conversely, if the read address catches up to the write address from behind,
// the buffer is empty and all reads halt until after a write happens.  In
// this case, the wrap-around bits are identical.

    reg  toggle_buffer_write_addr_wrap_around = 1'b0;
    wire buffer_write_addr_wrap_around;

    Register_Toggle
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    write_wrap_around_bit
    (
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (clear),
        .toggle         (toggle_buffer_write_addr_wrap_around),
        .data_in        (buffer_write_addr_wrap_around),
        .data_out       (buffer_write_addr_wrap_around)
    );

    reg  toggle_buffer_read_addr_wrap_around = 1'b0;
    wire buffer_read_addr_wrap_around;

    Register_Toggle
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    read_wrap_around_bit
    (
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (clear),
        .toggle         (toggle_buffer_read_addr_wrap_around),
        .data_in        (buffer_read_addr_wrap_around),
        .data_out       (buffer_read_addr_wrap_around)
    );

//## Control Path

//### Buffer States

// We describe the state of the buffer itself as the number of items currently
// stored in the buffer, as indicated by the read and write addresses and
// their wrap-around bits. We only care about the extremes: if the buffer
// holds no items, or if it holds its maximum number of items, as explained
// above.

    reg stored_items_zero = 1'b0;
    reg stored_items_max  = 1'b0;

    always @(*) begin
        stored_items_zero = (buffer_read_addr == buffer_write_addr) && (buffer_read_addr_wrap_around == buffer_write_addr_wrap_around);
        stored_items_max  = (buffer_read_addr == buffer_write_addr) && (buffer_read_addr_wrap_around != buffer_write_addr_wrap_around);
    end

//### Input Interface (Insert)

// The input interface is simple: if the buffer isn't at its maximum capacity,
// signal the input is ready, and when an input handshake completes, write the
// data directly into the buffer and increment the write address, wrapping
// around as necessary.

// In Circular Buffer Mode, the input is always ready. If the buffer is full,
// we insert by ovewriting the second oldest value (in the buffer) as it is
// removed and placed into the output register (which held the oldest value).

    reg insert = 1'b0;

    always @(*) begin
        input_ready                             = (stored_items_max == 1'b0) || (CIRCULAR_BUFFER != 0);
        insert                                  = (input_valid      == 1'b1) && (input_ready  == 1'b1);

        buffer_wren                             = (insert == 1'b1);
        increment_buffer_write_addr             = (insert == 1'b1);
        load_buffer_write_addr                  = (increment_buffer_write_addr == 1'b1) && (buffer_write_addr == ADDR_LAST [ADDR_WIDTH-1:0]);
        toggle_buffer_write_addr_wrap_around    = (load_buffer_write_addr      == 1'b1);
    end

//### Output Interface (Remove)

// The output interface is not so simple because the output is registered, and
// so holds data independently of the buffer. We signal the output holds valid
// data whenever we can remove an item from the buffer and load it into the
// output register. We meet this condition if the output register holds valid
// data and an output handshake completes, or if the buffer holds an item but
// the output register is not holding any valid data.  Also, we do not
// increment/wrap the read address if the previous item removed from the
// buffer and loaded into the output register was the last one.

// In Circular Buffer Mode, if the buffer is full and we insert a new data
// value, perform a remove operation, discarding the contents of the output
// register and replacing it with the next oldest entry in the buffer, as if
// it had been read out.

    reg remove_normal           = 1'b0;
    reg remove_circular         = 1'b0;
    reg remove                  = 1'b0;
    reg output_leaving_idle     = 1'b0;
    reg load_output_register    = 1'b0;

    always @(*) begin
        remove_normal                       = (output_valid    == 1'b1) && (output_ready        == 1'b1);
        remove_circular                     = (CIRCULAR_BUFFER !=    0) && (stored_items_max    == 1'b1) && (insert == 1'b1);
        remove                              = (remove_normal   == 1'b1) || (remove_circular     == 1'b1);
        output_leaving_idle                 = (output_valid    == 1'b0) && (stored_items_zero   == 1'b0);
        load_output_register                = (remove          == 1'b1) || (output_leaving_idle == 1'b1);

        buffer_rden                         = (load_output_register       == 1'b1) && (stored_items_zero == 1'b0);
        increment_buffer_read_addr          = (load_output_register       == 1'b1) && (stored_items_zero == 1'b0);
        load_buffer_read_addr               = (increment_buffer_read_addr == 1'b1) && (buffer_read_addr  == ADDR_LAST [ADDR_WIDTH-1:0]);
        toggle_buffer_read_addr_wrap_around = (load_buffer_read_addr      == 1'b1);
    end

// `output_valid` must be registered to match the latency of the buffer output
// register.

    Register
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    output_data_valid
    (
        .clock          (clock),
        .clock_enable   (load_output_register == 1'b1),
        .clear          (clear),
        .data_in        (stored_items_zero == 1'b0),
        .data_out       (output_valid)
    );

endmodule

//# Pipeline Credit Buffer

// Pipelines the control and data of a ready/valid hanshake with zero or more
// plain [Registers](./Register.html) and
// a [FIFO](./Pipeline_FIFO_Buffer.html) to control the propagation delay and
// increase the possible clock frequency.  The latency from input to output is
// `PIPE_DEPTH` cycles, plus 2 from the output FIFO.

// In a nutshell, a credit buffer has an input interface which knows the
// latency of the register pipeline, tracks how many data transfers have been
// sent from the input interface to the output interface (which subtracts from
// the credit count), tracks how many transfers have left the output interface
// (which adds to the credit count), and thus how much capacity (credit)
// remains in the output interface buffer (minus any data in-flight in the
// pipeline). With that information, we can modulate when the input interface
// can accept new transfers. The FIFO at the output interface is necessary to
// receive any transfers still in-flight in the register pipelines while the
// input interface does not accept new transfers (credit is zero).

// Unlike a [Skid Buffer Pipeline](./Skid_Buffer_Pipeline.html), a Credit
// Buffer Pipeline can also improve concurrency by absorbing any
// irregularities in the transfer rates of the input and output interfaces: if
// one interface stalls, the other interface will not see that stall for as
// long as there is either enough available data or space in the FIFO.

// For longer pipelines, a Credit Buffer Pipeline uses less hardware than
// a Skid Buffer Pipeline, especially if the FIFO fits inside a denser Block
// RAM, and may fit some underlying devices better (e.g.: the routing
// hyper-registers in high-end Intel FPGAs). For reference, see Abbas and Betz
// ["Latency Insensitive Design Styles for FPGAs"](./reading.html#elastic)
// (FPL, 2018).

//## Configuration

// The `PIPE_DEPTH` parameter specifies the number of pipeline registers on
// the `input_ready` and `input_valid/input_data` paths. Adjust `PIPE_DEPTH`
// to break any critical paths between ready/valid interfaces. A value of zero
// will not implement any pipeline registers and reduces the design to a very
// short FIFO (see below for minimum size calculation).  

// The `FIFO_DEPTH` parameter specifies the depth of the FIFO buffer before
// the output port.  The minimum FIFO depth for correct operation and to
// support full throughput is the sum of:

// * `PIPE_DEPTH`: enough for the FIFO to completely receive the contents of
// the pipeline registers. 
// * `PIPE_DEPTH` again: to allow for the credits from completed output
// handshakes to reach the input interface before credits run out.
// * 2 cycles to account for the input/output FIFO latency.
// * 1 cycle to account for updating the credit counter.

// If the given `FIFO_DEPTH` parameter is smaller than this sum, it is
// automatically adjusted internally to this minimum sum. You can also specify
// a `FIFO_DEPTH` *larger* than this sum to allow the FIFO to absorb stalls on
// the input and output interfaces of duration less than or equal to the extra
// FIFO depth, which will improve concurrency.  Adjust the `FIFO_RAMSTYLE`
// parameter to match your desired FIFO implementation and your target device.

//## Reset

// The pipeline registers do not have enable or reset logic: they are plain,
// always-on registers, which minimises wiring and logic, and matches the
// Intel hyper-register implementation. Thus, **you must hold `clear` active
// for `PIPE_DEPTH`+1 cycles at a minimum to make sure all in-flight data and
// control signals have been flushed**, else you might release `clear` and
// start processing stale data/control still in the pipeline, or place the
// entire pipeline in an inconsistent state resulting in data loss at a much
// later time.

//## Ports and Parameters

`default_nettype none

module Pipeline_Credit_Buffer
#(
    parameter WORD_WIDTH    = 0,
    parameter PIPE_DEPTH    = 0,
    parameter FIFO_DEPTH    = 0,
    parameter FIFO_RAMSTYLE = ""
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire                        input_valid,
    output  reg                         input_ready,
    input   wire    [WORD_WIDTH-1:0]    input_data,

    output  wire                        output_valid,
    input   wire                        output_ready,
    output  wire    [WORD_WIDTH-1:0]    output_data
);

    initial begin
        input_ready = 1'b1; // Empty at start, so accept data.
    end

// We need a minimum of 2x the pipeline latency in FIFO space to account for
// a full round-trip of the control signals, plus any other cycles of latency,
// so we don't stall prematurely or lose data.

    `include "max_function.vh"

    localparam COUNTER_LATENCY_CYCLES   = 1;
    localparam FIFO_LATENCY_CYCLES      = 2;
    localparam FIFO_DEPTH_MINIMUM       = (2 * PIPE_DEPTH) + FIFO_LATENCY_CYCLES + COUNTER_LATENCY_CYCLES;
    localparam FIFO_DEPTH_ADJUSTED      = max(FIFO_DEPTH, FIFO_DEPTH_MINIMUM); 

// As always, in a ready/valid handshake interface, data transfers and state
// changes can only happen when both ready and valid are asserted (the
// handshake completes). So we calculate those conditions for both interfaces
// here.

    reg input_handshake_done  = 1'b0;
    reg output_handshake_done = 1'b0;

    always @(*) begin
        input_handshake_done =  (input_valid  == 1'b1) && (input_ready  == 1'b1);
        output_handshake_done = (output_valid == 1'b1) && (output_ready == 1'b1);
    end

//## Input Interface

// The input interface is modulated by the credit counter: as long as we have
// send credits, we signal that we are ready to accept data.  Then we send off
// the data and valid pulses, and receive the ready pulses, both through
// simple register pipelines to reduce cycle time.

// The send credit counter starts by assuming everything is empty, so it has
// `FIFO_DEPTH_ADJUSTED` credits available to use.  We add one to the counter
// width to guarantee we can always contain the `FIFO_DEPTH_ADJUSTED` count
// plus the extra state of zero (no credits).

    `include "clog2_function.vh"

    localparam CREDIT_COUNTER_INITIAL   = FIFO_DEPTH_ADJUSTED;
    localparam CREDIT_COUNTER_WIDTH     = clog2(CREDIT_COUNTER_INITIAL) + 1;
    localparam CREDIT_COUNTER_ZERO      = {CREDIT_COUNTER_WIDTH{1'b0}};   
    localparam CREDIT_COUNTER_ONE       = {{CREDIT_COUNTER_WIDTH-1{1'b0}},1'b1};   

    reg                             credit_up_down = 1'b0; // 0/1 --> up/down
    reg                             credit_update  = 1'b0;
    wire [CREDIT_COUNTER_WIDTH-1:0] credit_available;

    Counter_Binary
    #(
        .WORD_WIDTH     (CREDIT_COUNTER_WIDTH),
        .INCREMENT      (CREDIT_COUNTER_ONE),
        .INITIAL_COUNT  (CREDIT_COUNTER_INITIAL [CREDIT_COUNTER_WIDTH-1:0])
    )
    send_credits
    (
        .clock          (clock),
        .clear          (clear),

        .up_down        (credit_up_down), // 0/1 --> up/down
        .run            (credit_update),

        .load           (1'b0),
        .load_count     (CREDIT_COUNTER_ZERO),

        .carry_in       (1'b0),
        // verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        // verilator lint_on  PINCONNECTEMPTY

        .count          (credit_available)
    );

//## Pipelines

// The pipelines are simple registers with no control logic which are always
// enabled and cannot be cleared: if it was possible to control them from the
// input/output interfaces and meet timing, we wouldn't need a pipeline!

// First, we continuously pipeline the data from the input interface to the
// output interface.

    wire [WORD_WIDTH-1:0] input_data_pipelined;

    Register_Pipeline_Simple
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .PIPE_DEPTH     (PIPE_DEPTH)
    )
    input_data_pipe
    (
        // If PIPE_DEPTH is zero, these are unused
        // verilator lint_off UNUSED
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (1'b0),
        // verilator lint_on  UNUSED
        .pipe_in        (input_data),
        .pipe_out       (input_data_pipelined)
    );

// Then, in parallel, we continuously pipeline a bit which indicates that the
// pipelined input data in the current cycle comes from a completed input
// handshake and is thus valid.

    wire input_handshake_done_pipelined;

    Register_Pipeline_Simple
    #(
        .WORD_WIDTH     (1),
        .PIPE_DEPTH     (PIPE_DEPTH)
    )
    input_handshake_pipe
    (
        // If PIPE_DEPTH is zero, these are unused
        // verilator lint_off UNUSED
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (1'b0),
        // verilator lint_on  UNUSED
        .pipe_in        (input_handshake_done),
        .pipe_out       (input_handshake_done_pipelined)
    );

// Similarly and in parallel we continuously pipeline, from the output interface
// back to the input interface, a bit which indicates that an output handshake
// has completed in the current cycle and thus a space has been freed in the FIFO.

    wire output_handshake_done_pipelined;

    Register_Pipeline_Simple
    #(
        .WORD_WIDTH     (1'b1),
        .PIPE_DEPTH     (PIPE_DEPTH)
    )
    output_handshake_pipe
    (
        // If PIPE_DEPTH is zero, these are unused
        // verilator lint_off UNUSED
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (1'b0),
        // verilator lint_on  UNUSED
        .pipe_in        (output_handshake_done),
        .pipe_out       (output_handshake_done_pipelined)
    );

//## Output Interface

// Finally, we store any valid pipelined input data into a FIFO until it can
// be read out. The FIFO itself is the output interface.

    Pipeline_FIFO_Buffer
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .DEPTH          (FIFO_DEPTH_ADJUSTED),
        .RAMSTYLE       (FIFO_RAMSTYLE)
    )
    output_storage
    (
        .clock          (clock),
        .clear          (clear),

        .input_valid    (input_handshake_done_pipelined),
        // verilator lint_off PINCONNECTEMPTY
        .input_ready    (),
        // verilator lint_on  PINCONNECTEMPTY
        .input_data     (input_data_pipelined),

        .output_valid   (output_valid),
        .output_ready   (output_ready),
        .output_data    (output_data)
    );

//## Control Logic

// The control logic for the `send_credits` counter is simple: at each cycle, if
// the input handshake completes, decrement the credit counter by one, if the
// output handshake completes, increment the credit counter by one, if both
// complete at the same time or no handshake completes this cycle, the counter
// stays constant.  So long as the send credit count is not zero, we can
// accept input data and send it through the pipeline.

    always @(*) begin
        credit_up_down  = (output_handshake_done_pipelined == 1'b0); // 0/1 --> up/down
        credit_update   = (output_handshake_done_pipelined != input_handshake_done);
        input_ready     = (credit_available != CREDIT_COUNTER_ZERO);
    end

endmodule

//# Pipeline Stall Smoother

// Prevents pipeline stalls at the output interface, given a known maximum
// input pipeline stall duration, by buffering a sufficient number of items
// from the input pipeline before allowing the output pipeline to start
// providing data.

// This controlled buffering allows any periodic stalls at the input (e.g. CDC
// latency) to resolve before the output runs out of data, thus ensuring an
// uninterrupted flow of data at the output once started.  Once started, the
// output provides data continuously until it stalls from lack of input data,
// then the buffering starts again.

// Alternately, if the input data meets an externally calculated trigger
// condition (e.g.: the end of a packet), the output will begin providing data
// only after sufficient time has passed (assuming 1 cycle/transfer), even if
// not enough items have arrived, to ensure that any pending input stall has
// time to complete and thus not stall the continuous output.

// *This whole mechanism depends on the average input and output data rates
// being identical, otherwise propagating stalls between input and output is
// inevitable.* You can externally detect an input stall propagated to the
// output by using a [Pulse Generator](./Pulse_Generator.html) to detect
// a negative edge on the `output_valid` port.

//## Parameters

// Set `WORD_WIDTH` to the width in bits of each transfer. Set `RAMSTYLE` to
// control the implementation of the FIFO buffer storage (see your CAD tool
// and target device for available option). Set `GATE_DATA` to a non-zero
// value to zero-out `output_data` when waiting to start output transfers.
// Select `GATE_IMPLEMENTATION` to best match your CAD tools and FPGA device,
// but it can virtually always be left as "AND".

// Note that if you want to precisely control the FIFO storage size (e.g.: to
// use up exactly one Block RAM), you must make `MAX_STALL_CYCLES` equal to
// the depth of your desired storage *minus one*. Values below 2 will be
// adjusted back up to 2, using up a total of 3 FIFO storage locations.

//## Ports and Constants

`default_nettype none

module Pipeline_Stall_Smoother
#(
    parameter       WORD_WIDTH          = 0,
    parameter       RAMSTYLE            = "",
    parameter       MAX_STALL_CYCLES    = 0,
    parameter       GATE_DATA           = 0,
    parameter       GATE_IMPLEMENTATION = "AND"
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire                        input_valid,
    output  wire                        input_ready,
    input   wire    [WORD_WIDTH-1:0]    input_data,

    input   wire                        input_trigger, // Preferably a one-cycle pulse high

    output  wire                        output_valid,
    input   wire                        output_ready,
    output  wire    [WORD_WIDTH-1:0]    output_data
);

// The `Pipeline_FIFO_Buffer` has a latency from input to output of 2 cycles,
// so we cannot specify a shorter input stall duration: single-cycle stalls are
// treated as two-cycle stalls.

// Also, to prevent creating a 1-cycle stall at the input when the FIFO buffer
// fills sufficiently to absorb the specified maximum input stall duration, we
// must add 1 to the specified `MAX_STALL_CYCLES` so that we have 1 storage
// location left to take in input during the cycle the first buffered output
// is sent out.

    `include "clog2_function.vh"
    `include "max_function.vh"

    localparam FIFO_DEPTH = max(MAX_STALL_CYCLES, 2) + 1;

//## Stored Item Counting

// Since the stored data count has to be able to represent `FIFO_DEPTH` itself, and
// not a zero to `FIFO_DEPTH-1` count of that quantity, we need an extra bit to
// guarantee sufficient range.

    localparam BUFFER_COUNT_WIDTH  = clog2(FIFO_DEPTH) + 1;
    localparam BUFFER_COUNT_ONE    = {{BUFFER_COUNT_WIDTH-1{1'b0}},1'b1};
    localparam BUFFER_COUNT_ZERO   = {BUFFER_COUNT_WIDTH{1'b0}};
    localparam BUFFER_COUNT_LAST   = FIFO_DEPTH [BUFFER_COUNT_WIDTH-1:0];
    localparam BUFFER_COUNT_UP     = 1'b0;
    localparam BUFFER_COUNT_DOWN   = 1'b1;

    reg                             buffer_count_up_down   = BUFFER_COUNT_UP;
    reg                             buffer_count_run       = 1'b0;
    wire [BUFFER_COUNT_WIDTH-1:0]   items_in_buffer;

    Counter_Binary
    #(
        .WORD_WIDTH     (BUFFER_COUNT_WIDTH),
        .INCREMENT      (BUFFER_COUNT_ONE),
        .INITIAL_COUNT  (BUFFER_COUNT_ZERO)
    )
    buffer_occupancy
    (
        .clock          (clock),
        .clear          (clear),

        .up_down        (buffer_count_up_down), // 0/1 --> up/down
        .run            (buffer_count_run),

        .load           (1'b0),
        .load_count     (BUFFER_COUNT_ZERO),

        .carry_in       (1'b0),
        //verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        //verilator lint_on  PINCONNECTEMPTY

        .count          (items_in_buffer)
    );

//## Trigger Delay 

// Since the delay count has to be able to represent `FIFO_DEPTH` itself, and
// not a zero to `FIFO_DEPTH-1` count of that quantity, we need an extra bit to
// guarantee sufficient range.

    localparam TRIGGER_COUNT_WIDTH  = clog2(FIFO_DEPTH) + 1;
    localparam TRIGGER_COUNT_ONE    = {{TRIGGER_COUNT_WIDTH-1{1'b0}},1'b1};
    localparam TRIGGER_COUNT_ZERO   = {TRIGGER_COUNT_WIDTH{1'b0}};
    localparam TRIGGER_COUNT_LAST   = FIFO_DEPTH [TRIGGER_COUNT_WIDTH-1:0];
    localparam TRIGGER_COUNT_UP     = 1'b0;

    reg                             trigger_count_reload    = 1'b0;
    reg                             trigger_count_run       = 1'b0;
    wire [TRIGGER_COUNT_WIDTH-1:0]  cycles_since_trigger;

    Counter_Binary
    #(
        .WORD_WIDTH     (TRIGGER_COUNT_WIDTH),
        .INCREMENT      (TRIGGER_COUNT_ONE),
        .INITIAL_COUNT  (TRIGGER_COUNT_ZERO)
    )
    trigger_delay
    (
        .clock          (clock),
        .clear          (clear),

        .up_down        (TRIGGER_COUNT_UP), // 0/1 --> up/down
        .run            (trigger_count_run),

        .load           (trigger_count_reload),
        .load_count     (TRIGGER_COUNT_ZERO),

        .carry_in       (1'b0),
        //verilator lint_off PINCONNECTEMPTY
        .carry_out      (),
        .carries        (),
        .overflow       (),
        //verilator lint_on  PINCONNECTEMPTY

        .count          (cycles_since_trigger)
    );

//## Stored Item Buffering

    wire                    output_valid_internal;
    wire                    output_ready_internal;
    wire [WORD_WIDTH-1:0]   output_data_internal;

    Pipeline_FIFO_Buffer
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .DEPTH          (FIFO_DEPTH),
        .RAMSTYLE       (RAMSTYLE)
    )
    smoothing_buffer
    (
        .clock          (clock),
        .clear          (clear),

        .input_valid    (input_valid),
        .input_ready    (input_ready),
        .input_data     (input_data),

        .output_valid   (output_valid_internal),
        .output_ready   (output_ready_internal),
        .output_data    (output_data_internal)
    );

//## Control Logic

// Buffer the input data in the `smoothing_buffer` until there is enough to
// absorb `MAX_STALL_CYCLES` cycles of input stall, then allow that buffered
// data to exit the output. If we run out of buffered data (which should never
// happen during steady flow state with a known maximum input stall duration),
// then revert back to buffering data.

    localparam STATE_BUFFERING = 1'b0;
    localparam STATE_SENDING   = 1'b1; 

    wire state;
    reg  state_next = STATE_BUFFERING;

    Register
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (STATE_BUFFERING)
    )
    state_storage
    (
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (clear),
        .data_in        (state_next),
        .data_out       (state)
    );

// Common logic for control. Everything must follow the state of the
// interfaces, else data can get lost.

    reg input_handshake_done    = 1'b0;
    reg output_handshake_done   = 1'b0;

    always @(*) begin
        input_handshake_done    = (input_valid  == 1'b1) && (input_ready  == 1'b1);
        output_handshake_done   = (output_valid == 1'b1) && (output_ready == 1'b1);
    end

// Control the buffer counter. Increment when data enters, decrement when data
// leaves, and stay constant otherwise.

    always @(*) begin
        buffer_count_run        = (input_handshake_done != output_handshake_done);
        buffer_count_up_down    = (input_handshake_done == 1'b0) && (output_handshake_done == 1'b1) ? BUFFER_COUNT_DOWN : BUFFER_COUNT_UP;
        buffer_count_up_down    = (input_handshake_done == 1'b1) && (output_handshake_done == 1'b0) ? BUFFER_COUNT_UP   : buffer_count_up_down;
    end

// Control the trigger counter. Start counting when a trigger is seen. Reset
// when sending begins, which is when this counter completes, at least.

    reg  trigger_clear = 1'b0;
    wire trigger_latched;

    Pulse_Latch
    #(
        .RESET_VALUE    (1'b0)
    )
    capture_trigger
    (
        .clock          (clock),
        .clear          (trigger_clear),
        .pulse_in       (input_trigger),
        .level_out      (trigger_latched)
    );

    always @(*) begin
        trigger_count_run       = (trigger_latched      == 1'b1);
        trigger_count_reload    = (cycles_since_trigger == TRIGGER_COUNT_LAST);
        trigger_clear           = (trigger_count_reload == 1'b1);
    end

// Calculate the next state. Buffer until full or until trigger. Then send
// until empty, then buffer again.

    always @(*) begin
        state_next              = (items_in_buffer == BUFFER_COUNT_LAST) || (cycles_since_trigger == TRIGGER_COUNT_LAST) ? STATE_SENDING   : state;
        state_next              = (items_in_buffer == BUFFER_COUNT_ZERO)                                                 ? STATE_BUFFERING : state_next;
    end

// If we are not sending data, gate the output handshake, and optionally gate
// the data also.

    Pipeline_Gate
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .IMPLEMENTATION (GATE_IMPLEMENTATION),
        .GATE_DATA      (GATE_DATA)
    )
    output_gate
    (
        .enable         (state == STATE_SENDING),

        .input_ready    (output_ready_internal),
        .input_valid    (output_valid_internal),
        .input_data     (output_data_internal),

        .output_valid   (output_valid),
        .output_ready   (output_ready),
        .output_data    (output_data)
    );

endmodule

//# Skid Buffer Pipeline

// Pipelines the path of a ready/valid handshake with zero or more [Skid
// Buffers](./Pipeline_Skid_Buffer.html) to control the propagation delay and
// increase the possible clock frequency. The latency from input to output is
// `PIPE_DEPTH` cycles. This module is a variation of the [Simple Register
// Pipeline](./Register_Pipeline_Simple.html).

// Unlike a [Pipeline FIFO Buffer](./Pipeline_FIFO_Buffer.html), a Skid Buffer
// Pipeline will not improve concurrency by absorbing any irregularities in
// the transfer rates of the input and output interfaces: if one interface
// stalls, the other interface will eventually see that stall. However, a FIFO
// buffer will not add much pipelining.

// Alternatively, if you can afford a FIFO or if your hardware supports it
// well, you may want to use a [Pipeline Credit
// Buffer](./Pipeline_Credit_Buffer.html) instead, which might use less
// hardware for longer pipelines and has both the pipelining benefits of
// a Skid Buffer Pipeline and the buffering of a FIFO.

// `clear` sets all registers to zero. If `PIPE_DEPTH` is zero, the input
// handshake ports becomes directly wired to the output handshake ports and no
// logic is inferred.

`default_nettype none

module Skid_Buffer_Pipeline
#(
    parameter WORD_WIDTH =  0,
    parameter PIPE_DEPTH = -1
)
(
    // If PIPE_DEPTH is zero, these are unused
    // verilator lint_off UNUSED
    input   wire                        clock,
    input   wire                        clear,
    // verilator lint_on  UNUSED
    input   wire                        input_valid,
    output  wire                        input_ready,
    input   wire    [WORD_WIDTH-1:0]    input_data,

    output  reg                         output_valid,
    input   wire                        output_ready,
    output  reg     [WORD_WIDTH-1:0]    output_data
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        output_valid = 1'b0;
        output_data  = WORD_ZERO;
    end

    genvar i;
    generate
        if (PIPE_DEPTH == 0) begin
            assign input_ready  = output_ready;
            always @(*) begin
                output_valid = input_valid;
                output_data  = input_data;
            end
        end
        else if (PIPE_DEPTH > 0) begin

// We strip out first iteration of Skid Buffer instantiations to avoid having
// to refer to index -1 in the generate loop, and also to connect to the input
// handshake ports rather than the output of a previous Skid Buffer.

            wire                  valid_pipe [PIPE_DEPTH-1:0];
            wire                  ready_pipe [PIPE_DEPTH-1:0];
            wire [WORD_WIDTH-1:0] data_pipe  [PIPE_DEPTH-1:0];

            Pipeline_Skid_Buffer
            #(
                .WORD_WIDTH      (WORD_WIDTH),
                .CIRCULAR_BUFFER (0)            // Not meaningful here
            )
            input_stage
            (
                .clock          (clock),
                .clear          (clear),

                .input_valid    (input_valid),
                .input_ready    (input_ready),
                .input_data     (input_data),

                .output_valid   (valid_pipe[0]),
                .output_ready   (ready_pipe[0]),
                .output_data    (data_pipe [0])
            );

// Now repeat over the remainder of the pipeline stages, starting at stage 1,
// connecting each pipeline stage to the output of the previous pipeline
// stage.

            for (i=1; i < PIPE_DEPTH; i=i+1) begin: pipe_stages
                Pipeline_Skid_Buffer
                #(
                    .WORD_WIDTH      (WORD_WIDTH),
                    .CIRCULAR_BUFFER (0)            // Not meaningful here
                )
                pipe_stage
                (
                    .clock          (clock),
                    .clear          (clear),

                    .input_valid    (valid_pipe[i-1]),
                    .input_ready    (ready_pipe[i-1]),
                    .input_data     (data_pipe [i-1]),

                    .output_valid   (valid_pipe[i]),
                    .output_ready   (ready_pipe[i]),
                    .output_data    (data_pipe [i])
                );
            end

// And finally, connect the output handshake ports of the last Skid Buffer to
// the module output handshake ports.

            assign ready_pipe [PIPE_DEPTH-1] = output_ready;
            always @(*) begin
                output_valid = valid_pipe[PIPE_DEPTH-1];
                output_data  = data_pipe [PIPE_DEPTH-1];
            end
        end
    endgenerate

endmodule

